noncompliant:
// Noncompliant: Locale not set for DataTable
using System;
using System.Data;

namespace MyLibrary
{
    public class Foo
    {
        public DataTable CreateTable()
        {
            DataTable table = new DataTable("Customers"); // Noncompliant
            return table;
        }
    }
}

compliant:
// Compliant: Locale explicitly set to InvariantCulture
using System;
using System.Data;
using System.Globalization;

namespace MyLibrary
{
    public class Foo
    {
        public DataTable CreateTable()
        {
            DataTable table = new DataTable("Customers");
            table.Locale = CultureInfo.InvariantCulture; // Compliant
            return table;
        }
    }
}

// Compliant: DataSet with locale set
var dataSet = new DataSet();
dataSet.Locale = CultureInfo.InvariantCulture; // Compliant
